[
  {
    "text": "We provide the first polynomial-time constant-factor approximation of the Gromov-Hausdorff distance between finite point sets in the Euclidean plane.",
    "topic": "Gromov-Hausdorff distance approximation"
  },
  {
    "text": "The bijective (bottleneck) Gromov-Hausdorff distance \(d_{GH}^{bij}\) between equal-size sets satisfies \(\max_{i,j}|d_X(i,j) - d_Y(\sigma i, \sigma j)| = 2\,d_{GH}^{bij}\), which we approximate within an absolute constant.",
    "topic": "Bijective Gromov-Hausdorff distance"
  },
  {
    "text": "Hall and Papadimitriou (2005) showed a 2-approximation for additive distortion on the line and proved that achieving an approximation within 3 is NP-hard in dimension three, leaving the planar case open.",
    "topic": "Additive distortion approximation hardness"
  },
  {
    "text": "The algorithm uses a fat-or-collinear dichotomy: fat sets are aligned by a single rigid motion, while near-collinear sets are split into clusters matched along their dendrogram in a flat, scale-free pass, with orientations and reflection signs recovered by global cuts.",
    "topic": "Fat-or-collinear dichotomy"
  },
  {
    "text": "Relaxing bijections to correspondences reduces the problem to a within-cluster-multiplicity kernel, which the same theory closes, yielding the Gromov-Hausdorff distance itself.",
    "topic": "Correspondences and Gromov-Hausdorff distance"
  }
]
